INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000000', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'text', '{"html":"<h3>What this review is and how to use it</h3><p>This module is a <strong>high-yield review</strong>, not a from-scratch course. It assumes you have already studied each topic and now want to refresh the formulas, work representative problems, and lock in the exam tips that win points. In Texas, the entry credential is the <strong>Surveyor-in-Training (SIT)</strong>, and the gate to it is the <strong>NCEES Fundamentals of Surveying (FS) exam</strong>. Pass the FS, meet the education requirement, and TBPELS issues the SIT &mdash; the credential under which you accrue qualifying experience toward the RPLS.</p><p>The FS is a <strong>computer-based test (CBT)</strong> delivered at Pearson VUE centers. It is multiple-choice, with a fixed total of about <strong>110 questions</strong> in roughly <strong>5 hours 20 minutes</strong> (about 6 hours total with the tutorial and a scheduled break). It is <strong>closed-book</strong> except for the on-screen, searchable <strong>NCEES FS Reference Handbook</strong> &mdash; the only reference you may use. Knowing where formulas live in that handbook is itself an exam skill.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000001', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'text', '{"html":"<h3>Topic areas and weighting</h3><p>The FS exam blueprint spreads questions across the surveying fundamentals. Exact counts shift between specification updates, but the practical weighting for review purposes is stable: spend the most time where the most questions are. The computational core &mdash; <strong>mathematics, measurements and error theory, distance/angle measurement, leveling, traverse and coordinate geometry, and area</strong> &mdash; dominates the exam. Conceptual blocks &mdash; <strong>GNSS/positioning, geodesy/datums, photogrammetry/imaging, and professional practice/standards</strong> &mdash; round it out.</p><p>The remaining lessons in this module map onto those blocks. Treat each as a checklist: if you can work its problems quickly and explain its key formulas, you are ready for that slice of the exam. If you stall, that lesson flags where to drill.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000002', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'table', '{"headers":["FS topic area (review block)","Roughly","Where reviewed here"],"rows":[["Mathematics, units, geometry/trig","High","Lesson 2"],["Measurements, error theory, statistics","High","Lesson 3"],["Distance & angle measurement, instruments","High","Lesson 4"],["Leveling & vertical control","Medium","Lesson 5"],["Coordinate systems & geodesy/datums","Medium","Lesson 6"],["Traverse & coordinate computations","High","Lesson 7"],["Area & volume","Medium","Lesson 8"],["GPS/GNSS positioning","Medium","Lesson 9"],["Mixed problem practice","—","Lesson 10"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000003', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'callout', '{"type":"info","text":"Strategy: the FS rewards speed and accuracy on routine computations. You have roughly 2.9 minutes per question. Bank time on the easy quantitative items so you can afford the harder conceptual ones — and so you have margin to recheck units and signs."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000004', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'text', '{"html":"<h3>Test-taking strategy that scores</h3><p>Three habits separate a comfortable pass from a near miss:</p><ul><li><strong>Read for the unit and the unknown first.</strong> Decide what is asked (degrees vs. radians, feet vs. meters, area vs. distance) before touching the calculator. Many distractor answers are the right number in the wrong unit.</li><li><strong>Set your calculator deliberately.</strong> Confirm degree mode for survey angles; the single most common silent error is a calculator left in radians.</li><li><strong>Estimate, then compute.</strong> A 10-second sanity estimate (the hypotenuse must exceed either leg; a bearing in the SE quadrant has an azimuth between 90&deg; and 180&deg;) catches gross errors and eliminates wrong choices.</li></ul><p>Use the handbook search aggressively for the exact constant or formula form (e.g., the steel-tape coefficient, the average-end-area volume formula). Do not try to memorize what you can look up; do memorize the <em>shape</em> of each computation so you recognize it instantly.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000005', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'callout', '{"type":"warning","text":"Avoidable point-losers: (1) calculator in radian mode; (2) mixing feet and meters, or US survey foot vs. international foot; (3) sign errors on latitudes/departures (S and W are negative); (4) forgetting to halve in the shoelace area or in the curve tangent R·tan(I/2); (5) using a zenith angle as if it were a vertical (slope) angle."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0001-0000-0000-000000000006', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'key_takeaways', '{"title":"Key Takeaways","items":["The FS exam is the gateway to the Texas SIT; it is CBT, ~110 questions, ~5h20m, closed-book except the NCEES FS Reference Handbook.","Weight your review toward the computational core: math, measurements/errors, distance/angles, leveling, traverse, area.","Budget ~2.9 min/question; bank time on routine computations to fund harder conceptual ones.","Prevent the classic point-losers: calculator mode, unit mismatches, and sign errors."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000000', '74470d18-37e1-4928-a697-46927b811835', 'text', '{"html":"<h3>The trig you will actually use</h3><p>Nearly every surveying computation reduces to a triangle. For a <strong>right triangle</strong>, the Pythagorean theorem and SOH-CAH-TOA cover almost everything: the hypotenuse is <strong>c = sqrt(a&sup2; + b&sup2;)</strong>, and the three primary ratios relate an acute angle to the opposite, adjacent, and hypotenuse sides. On the FS you will use these to reduce slope distances, decompose a course into north-south and east-west components, and solve offsets.</p><p>The key habit is <strong>identifying which sides you know</strong> and choosing the ratio that involves your unknown. If you know the hypotenuse and need the side opposite an angle, use sine; adjacent, cosine; if you know both legs and need the angle, use the inverse tangent (arctangent). Keep the calculator in <strong>degree mode</strong> for survey angles.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000001', '74470d18-37e1-4928-a697-46927b811835', 'equation', '{"latex":"c=\\sqrt{a^2+b^2}\\qquad \\sin\\theta=\\frac{\\text{opp}}{\\text{hyp}}\\quad \\cos\\theta=\\frac{\\text{adj}}{\\text{hyp}}\\quad \\tan\\theta=\\frac{\\text{opp}}{\\text{adj}}","label":"Right-triangle relations","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000002', '74470d18-37e1-4928-a697-46927b811835', 'text', '{"html":"<h3>Oblique triangles</h3><p>When no angle is 90&deg;, use the <strong>law of sines</strong> or <strong>law of cosines</strong>. Use the law of sines when you have an angle paired with its opposite side (ASA, AAS, or the ambiguous SSA); use the law of cosines when you have two sides and the included angle (SAS, to find the third side) or all three sides (SSS, to find an angle). These solve survey triangles such as a station occupied with two observed angles and one measured baseline.</p><p>Watch the <strong>SSA ambiguous case</strong>: the law of sines can yield two possible triangles. On the exam, the geometry of the problem (or a sketch) tells you which solution is physical &mdash; usually the one consistent with the stated configuration.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000003', '74470d18-37e1-4928-a697-46927b811835', 'equation', '{"latex":"\\frac{a}{\\sin A}=\\frac{b}{\\sin B}=\\frac{c}{\\sin C}\\qquad c^2=a^2+b^2-2ab\\cos C","label":"Law of sines and law of cosines","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000004', '74470d18-37e1-4928-a697-46927b811835', 'text', '{"html":"<h3>Units, angles, and conversions</h3><p>Surveyors juggle units constantly, and the FS punishes carelessness. Memorize the core conversions and confirm any constant in the handbook:</p><ul><li><strong>Length:</strong> 1 international foot = 0.3048 m exactly; 1 US survey foot = 1200/3937 m. The two differ by ~2 ppm &mdash; small per foot, but it matters over State Plane distances.</li><li><strong>Area:</strong> 1 acre = 43,560 ft&sup2;; 1 acre = 10 square chains; 640 acres = 1 section (1 sq mile).</li><li><strong>Angle:</strong> 1&deg; = 60&prime; = 3600&Prime;; radians = degrees &times; &pi;/180; a full circle = 360&deg; = 2&pi; rad. Some equipment reports in <strong>grads</strong> (gons): 400 grad = 360&deg;.</li></ul><p>To convert <strong>DMS to decimal degrees</strong>, add: deg + min/60 + sec/3600. To go back, take the whole degrees, multiply the fraction by 60 for minutes, and the leftover by 60 for seconds.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000005', '74470d18-37e1-4928-a697-46927b811835', 'table', '{"headers":["Quantity","Conversion"],"rows":[["Foot to meter (intl)","1 ft = 0.3048 m exactly"],["US survey foot","1 ft(US) = 1200/3937 m ≈ 0.30480061 m"],["Acre","1 acre = 43,560 ft² = 10 sq chains"],["Section","1 section = 640 acres = 1 sq mile"],["Degrees ↔ radians","rad = deg × π/180; deg = rad × 180/π"],["DMS to decimal","dd = d + m/60 + s/3600"],["Grads","400 grad = 360° (1 grad = 0.9°)"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000006', '74470d18-37e1-4928-a697-46927b811835', 'text', '{"html":"<h3>The inverse: distance and direction between two points</h3><p>Given two coordinate points with northing (N, the y-axis) and easting (E, the x-axis), the <strong>inverse computation</strong> returns the straight-line distance and the azimuth between them. The distance is the hypotenuse of the coordinate differences, and the azimuth (clockwise from north) is the arctangent of the east difference over the north difference:</p><p>Crucially, use the <strong>two-argument arctangent, atan2(&Delta;E, &Delta;N)</strong>, which places the result in the correct quadrant automatically; then add 360&deg; if negative so the azimuth lies in 0&ndash;360&deg;. A plain atan(&Delta;E/&Delta;N) loses the quadrant and is a frequent source of wrong answers.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000007', '74470d18-37e1-4928-a697-46927b811835', 'equation', '{"latex":"D=\\sqrt{(\\Delta E)^2+(\\Delta N)^2}\\qquad \\text{Az}=\\operatorname{atan2}(\\Delta E,\\ \\Delta N)\\ (\\text{reduce to }0\\text{–}360^\\circ)","label":"Inverse between two coordinates","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000008', '74470d18-37e1-4928-a697-46927b811835', 'callout', '{"type":"warning","text":"Exam trap: keep your calculator in DEGREE mode for survey angles. When inverting coordinates, remember azimuth = atan2(ΔE, ΔN) — easting over northing — not the reverse, and reduce a negative result by adding 360°."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0002-0000-0000-000000000009', '74470d18-37e1-4928-a697-46927b811835', 'key_takeaways', '{"title":"Key Takeaways","items":["Master right-triangle trig (c = sqrt(a²+b²), SOH-CAH-TOA) and oblique-triangle laws (sines, cosines).","Know the conversions cold: 0.3048 m/ft, 43,560 ft²/acre, deg = rad × 180/π, DMS = d + m/60 + s/3600.","Inverse: D = hypot(ΔE, ΔN); azimuth = atan2(ΔE, ΔN), reduced to 0–360°.","Confirm degree mode and watch the SSA ambiguous case and the US-vs-international foot."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000000', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'text', '{"html":"<h3>Three kinds of error</h3><p>Every measurement contains error; the skill is classifying it. <strong>Systematic errors</strong> follow a physical or instrumental law &mdash; tape too long, EDM scale error, a level out of adjustment. They accumulate in the same direction and can be <em>modeled and removed</em> by calibration or a correction formula. <strong>Random errors</strong> are the small, unavoidable fluctuations that remain after systematic effects are removed; they are equally likely to be plus or minus, follow the normal (Gaussian) distribution, and are handled <em>statistically</em>, never eliminated. <strong>Mistakes (blunders)</strong> &mdash; a transposed digit, a misread rod, the wrong target &mdash; are not errors in the statistical sense; they must be <em>detected and discarded</em>, typically through checks and redundancy.</p><p>On the FS, expect questions that ask you to <em>classify</em> a described error or to state how each type should be treated. The standard pairing: systematic &rarr; correct/calibrate; random &rarr; analyze statistically; blunder &rarr; find and remove.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000001', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'callout', '{"type":"info","text":"Memory hook: Systematic = a Sign you can correct (one direction). Random = Roams both ways (normal curve). Mistake = Must be Removed."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000002', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'text', '{"html":"<h3>Accuracy vs. precision</h3><p>These are not synonyms. <strong>Accuracy</strong> is how close a measurement is to the <em>true</em> value &mdash; it reflects <strong>bias</strong> (systematic error). <strong>Precision</strong> is how closely repeated measurements agree with <em>each other</em> &mdash; it reflects <strong>scatter</strong> (random error). The classic target analogy: tight grouping off-center is precise but inaccurate (a bias is present); a loose spread centered on the bullseye is accurate on average but imprecise. You want both: tight and centered.</p><p>This distinction drives practice. Repeating a measurement improves your knowledge of the mean (fights random error) but does <em>nothing</em> about a systematic bias &mdash; averaging a hundred reads of a mis-standardized tape still gives a biased answer. Bias is removed by calibration and corrections, not by repetition.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000003', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'text', '{"html":"<h3>Basic statistics of observations</h3><p>For n direct, equally weighted observations, the <strong>most probable value</strong> is the arithmetic <strong>mean</strong>. Each observation''s <strong>residual</strong> is v = observation &minus; mean. The spread is summarized by the <strong>sample standard deviation</strong>, using n&minus;1 in the denominator (Bessel''s correction) because one degree of freedom is consumed estimating the mean:</p><p>The standard deviation describes a single observation. The reliability of the <strong>mean itself</strong> improves with more observations: the <strong>standard deviation of the mean</strong> is &sigma; divided by the square root of n. This is why redundant observations help &mdash; but only as sqrt(n), so the fourth observation helps far less than the second.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000004', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'equation', '{"latex":"\\bar{x}=\\frac{\\sum x_i}{n}\\qquad \\sigma=\\sqrt{\\frac{\\sum v_i^{\\,2}}{n-1}}\\qquad \\sigma_{\\bar x}=\\frac{\\sigma}{\\sqrt{n}}","label":"Mean, standard deviation, std. dev. of the mean","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000005', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'table', '{"headers":["Confidence","Multiplier of σ (normal)"],"rows":[["≈ 50% (probable error)","0.6745 σ"],["68.3% (one sigma)","1.000 σ"],["90%","1.645 σ"],["95%","1.960 σ"],["99.7% (three sigma)","3.000 σ"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000006', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'text', '{"html":"<h3>Error propagation</h3><p>When a result is computed from several measured quantities, their errors combine. For a <strong>sum or difference</strong> of independent quantities, the errors add <strong>in quadrature</strong> (root-sum-square): the total error is the square root of the sum of the squared component errors. This is the single most-tested propagation rule on the FS.</p><p>Two important special cases follow directly. The <strong>error of a series</strong> of n equal, independent measurements (e.g., a taped line made in n equal tape lengths each with error E) is E&middot;sqrt(n). The <strong>error of the mean</strong> of n equal observations is E/sqrt(n) &mdash; the same sqrt(n) behavior we saw for the standard deviation of the mean. Recognize which case applies: accumulating along a line grows the error by sqrt(n); averaging shrinks it by sqrt(n).</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000007', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'equation', '{"latex":"E_{\\text{sum}}=\\sqrt{E_1^{2}+E_2^{2}+\\cdots+E_n^{2}}\\qquad E_{\\text{series}}=E\\sqrt{n}\\qquad E_{\\text{mean}}=\\frac{E}{\\sqrt{n}}","label":"Propagation: sum, series, and mean","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000008', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'callout', '{"type":"warning","text":"Exam trap: errors add in quadrature (root-sum-square), not arithmetically. Adding errors linearly overstates the combined error. And remember n−1 (not n) in the sample standard deviation."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0003-0000-0000-000000000009', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'key_takeaways', '{"title":"Key Takeaways","items":["Classify error: systematic (correct/calibrate), random (analyze statistically), mistake (find and discard).","Accuracy = closeness to truth (bias); precision = repeatability (scatter); averaging fights random error, not bias.","σ = sqrt(Σv²/(n−1)); σ of the mean = σ/sqrt(n); 95% ≈ 1.96σ.","Errors of a sum combine in quadrature; a series grows as E·sqrt(n), a mean shrinks as E/sqrt(n)."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000000', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'text', '{"html":"<h3>Slope to horizontal reduction</h3><p>Total stations and tapes measure along the line of sight (slope distance); boundary and mapping work needs <strong>horizontal distance</strong>. The reduction depends on which angle you have. With a <strong>vertical (slope) angle</strong> &alpha; measured up or down from horizontal, the horizontal distance is H = S&middot;cos&alpha;. With a <strong>zenith angle</strong> z measured down from the vertical (so a level sight reads 90&deg;), it is H = S&middot;sin z. The two are complements: z + &alpha; = 90&deg;.</p><p>This is a top exam trap. Confusing a zenith angle for a slope angle (using cosine when you should use sine, or vice versa) yields a plausible but wrong number. Read the problem: if a level shot would read 0&deg;, it is a vertical angle (use cosine); if a level shot would read 90&deg;, it is a zenith angle (use sine).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000001', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'equation', '{"latex":"H = S\\cos\\alpha = S\\sin z,\\qquad z = 90^\\circ-\\alpha","label":"Slope-to-horizontal reduction","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000002', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'text', '{"html":"<h3>Steel-tape corrections</h3><p>Although EDM dominates modern practice, the FS still tests <strong>taping corrections</strong> because they exercise systematic-error thinking. Each correction has a sign and a physical cause:</p><ul><li><strong>Temperature:</strong> Ct = &alpha;(T &minus; T0)L, with the steel coefficient &alpha; = 0.00000645 per &deg;F (T0 = 68&deg;F standard). Hotter tape is longer &rarr; correction added.</li><li><strong>Pull/tension:</strong> a tape pulled harder than standard stretches; Cp = (P &minus; P0)L/(A&middot;E).</li><li><strong>Sag:</strong> an unsupported tape hangs in a catenary and reads <em>too long</em>; the sag correction is negative, &minus;w&sup2;L&sup3;/(24P&sup2;) per span.</li><li><strong>Slope:</strong> to reduce a slope-taped length to horizontal, subtract approximately h&sup2;/(2L), where h is the elevation difference over the length L.</li><li><strong>Standardization:</strong> if the tape''s true length differs from nominal, scale the measured distance by (actual/nominal).</li></ul><p>Apply the right sign: corrections that make the line <em>longer</em> than measured are positive; those that shorten it are negative.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000003', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'table', '{"headers":["Correction","Formula","Sign / note"],"rows":[["Temperature","Ct = α(T − T0)L, α = 0.00000645/°F","+ if hotter than standard"],["Tension (pull)","Cp = (P − P0)L/(A·E)","+ if pulled harder than standard"],["Sag","Cs = −w²L³/(24P²) per span","always − (reads too long)"],["Slope to horizontal","≈ −h²/(2L)","always − (horizontal < slope)"],["Standardization","C = (actual − nominal)/nominal × L","sign of (actual − nominal)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000004', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'text', '{"html":"<h3>Bearings, azimuths, and angles from directions</h3><p>Direction is expressed two ways. An <strong>azimuth</strong> is measured <strong>clockwise from north, 0&deg; to 360&deg;</strong> &mdash; a single number, easy to compute with. A <strong>quadrant bearing</strong> is an acute angle (0&deg;&ndash;90&deg;) measured from north or south toward east or west, e.g., <em>N 40&deg;15&prime; E</em> or <em>S 62&deg; W</em>. Convert by quadrant:</p><ul><li><strong>NE:</strong> Az = bearing angle &beta;.</li><li><strong>SE:</strong> Az = 180&deg; &minus; &beta;.</li><li><strong>SW:</strong> Az = 180&deg; + &beta;.</li><li><strong>NW:</strong> Az = 360&deg; &minus; &beta;.</li></ul><p>To find the <strong>angle between two lines</strong>, subtract their azimuths (taking the absolute difference, and if it exceeds 180&deg;, subtract from 360&deg; for the interior angle). The <strong>back azimuth</strong> of a line is its forward azimuth &plusmn; 180&deg;.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000005', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Quadrant-to-azimuth conversion — NE: Az = β; SE: 180 − β; SW: 180 + β; NW: 360 − β."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000006', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'text', '{"html":"<h3>Angular misclosure of a closed traverse</h3><p>A closed polygon traverse has a built-in geometric check: the sum of the <strong>interior angles</strong> must equal <strong>(n &minus; 2) &times; 180&deg;</strong>, where n is the number of sides/angles. The <strong>angular misclosure</strong> is the measured sum minus this theoretical sum. If it falls within the allowable tolerance (commonly a per-station limit times sqrt(n)), distribute it by applying an equal correction of <strong>misclosure &divide; n</strong> to each angle.</p><p>For an exterior-angle traverse the sum is (n + 2) &times; 180&deg;; for a deflection-angle traverse the algebraic sum of deflection angles (right positive, left negative) is 360&deg; for a closed loop. Know all three forms, but the interior-angle rule is the most common FS question.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000007', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'equation', '{"latex":"\\sum\\theta_{\\text{int}}=(n-2)\\,180^\\circ,\\qquad \\text{correction/angle}=\\frac{\\text{misclosure}}{n}","label":"Interior-angle condition and balancing","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000008', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'callout', '{"type":"warning","text":"Exam trap: zenith angle (from vertical, level = 90°) uses H = S·sin z; vertical/slope angle (from horizontal, level = 0°) uses H = S·cos α. The sag correction is always negative — an unsupported tape reads too long."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0004-0000-0000-000000000009', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'key_takeaways', '{"title":"Key Takeaways","items":["H = S·cos(slope angle) = S·sin(zenith angle); they are complements (z = 90° − α).","Tape corrections: temperature Ct = α(T−T0)L (α = 0.00000645/°F); sag and slope are always negative.","Quadrant↔azimuth by quadrant (NE: β; SE: 180−β; SW: 180+β; NW: 360−β); back azimuth = forward ± 180°.","Interior angles sum to (n−2)·180°; balance by spreading the misclosure equally (÷ n)."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000000', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'text', '{"html":"<h3>Differential leveling: HI method</h3><p>Differential leveling transfers elevation from a known benchmark to new points using a level and a graduated rod. The workhorse is the <strong>height-of-instrument (HI) method</strong>. You read a <strong>backsight (BS)</strong> on a point of known elevation; that read is a <strong>plus sight</strong> because it is added: <strong>HI = known elevation + BS</strong>. The HI is the elevation of the instrument''s line of sight. To get a new point''s elevation, you read a <strong>foresight (FS)</strong> there &mdash; a <strong>minus sight</strong> &mdash; and subtract: <strong>elevation = HI &minus; FS</strong>.</p><p>Note the counterintuitive logic: a <em>high</em> rod reading means a <em>low</em> point (the line of sight hits higher up the rod). Backsights are added regardless of whether the point is uphill or downhill; foresights are subtracted. Keeping the plus/minus discipline straight is the whole game.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000001', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'equation', '{"latex":"HI = \\text{Elev}_{\\text{BM}} + BS,\\qquad \\text{Elev}_{\\text{new}} = HI - FS","label":"Height-of-instrument leveling","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000002', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'text', '{"html":"<h3>Turning points and intermediate sights</h3><p>When the next point of interest is out of sight or too far, the surveyor sets a <strong>turning point (TP)</strong> &mdash; a stable, temporary point on which the rod stays fixed while the instrument moves ahead. At a TP you take a <strong>foresight</strong> (to compute its elevation) and then, after moving the level, a <strong>backsight</strong> (to re-establish HI). The rod must not move between the FS and the following BS or the line of levels is broken.</p><p>An <strong>intermediate sight</strong> (or side shot) is a foresight to a point whose elevation you want but which is <em>not</em> used to carry the line forward; it does not become a TP and is not part of the loop''s BS/FS check. Only FS readings to TPs (and the final point) enter the arithmetic check below.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000003', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'table', '{"headers":["Term","Read on","Role"],"rows":[["Backsight (BS)","Point of known elevation","Plus sight: HI = Elev + BS"],["Foresight (FS)","Point of unknown elevation / TP","Minus sight: Elev = HI − FS"],["Turning point (TP)","Stable temporary point","Receives FS then BS to advance the line"],["Intermediate sight","Side point of interest","Elevation only; not a TP, not in BS/FS check"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000004', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'text', '{"html":"<h3>Loop closure and the arithmetic check</h3><p>A leveling run should be checked two ways. The <strong>arithmetic (page) check</strong> verifies the bookkeeping: the sum of all backsights minus the sum of all foresights must equal the final elevation minus the starting elevation. If it does not, you made a math error in the notes.</p><p>The <strong>loop misclosure</strong> verifies the field work: when you level around a loop back to the starting benchmark (or close on a second known benchmark), the computed elevation should match the known value. The difference is the misclosure, which must fall within an <strong>allowable error</strong> &mdash; commonly expressed as a constant times sqrt(distance in miles or kilometers), e.g., 0.05&middot;sqrt(M) ft for ordinary work. If within tolerance, the misclosure is distributed proportionally to the number of setups or the distance leveled.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000005', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'equation', '{"latex":"\\sum BS - \\sum FS = \\text{Elev}_{\\text{final}} - \\text{Elev}_{\\text{start}},\\qquad e_{\\text{allow}} = C\\sqrt{K}","label":"Arithmetic check and allowable loop misclosure","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000006', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'text', '{"html":"<h3>Systematic errors and how to cancel them</h3><p>Leveling has three classic systematic errors that grow with sight distance: <strong>collimation</strong> (the line of sight not truly horizontal), <strong>earth curvature</strong> (the level surface drops away), and <strong>atmospheric refraction</strong> (the sight bends). The elegant field fix is to <strong>balance backsight and foresight distances</strong> at each setup: when BS and FS lengths are equal, these errors affect both readings by the same amount and <em>cancel in the difference</em>. This is the single most important leveling technique to state on the exam.</p><p>Curvature and refraction together are often combined as a correction of about <strong>0.0206&middot;K&sup2;</strong> feet (K in thousands of feet) or 0.0675&middot;K&sup2; m (K in km), curvature lowering and refraction raising the apparent reading, with refraction roughly 1/7 of curvature. Other errors &mdash; rod not plumb, rod settlement at a TP &mdash; are minimized by good field procedure.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000007', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'callout', '{"type":"warning","text":"Exam trap: backsights are ALWAYS added and foresights ALWAYS subtracted, regardless of terrain — never key off whether the point is uphill or downhill. Balancing BS/FS distances cancels collimation, curvature, and refraction; an intermediate sight is not a turning point."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0005-0000-0000-000000000008', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'key_takeaways', '{"title":"Key Takeaways","items":["HI = known elevation + BS (plus sight); new elevation = HI − FS (minus sight).","A turning point receives a FS then a BS to carry the line forward; an intermediate sight does not.","Check: ΣBS − ΣFS = final − starting elevation; loop misclosure must be ≤ C·sqrt(distance).","Balance backsight and foresight distances to cancel collimation, curvature, and refraction."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000000', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'text', '{"html":"<h3>Datums: horizontal and vertical</h3><p>A <strong>datum</strong> is the reference framework that gives coordinates meaning. The modern <strong>horizontal datum</strong> in the U.S. is <strong>NAD83</strong>, realized on the <strong>GRS80 ellipsoid</strong> &mdash; a smooth mathematical surface approximating the Earth, on which geodetic latitude and longitude are defined. The modern <strong>vertical datum</strong> is <strong>NAVD88</strong>, which expresses <strong>orthometric heights</strong> (elevations) referenced to the <strong>geoid</strong>, the equipotential surface approximating mean sea level.</p><p>The geoid and the ellipsoid are different surfaces. GNSS measures height above the <em>ellipsoid</em> (ellipsoid height, h), but engineering and mapping need height above the <em>geoid</em> (orthometric height, H, which is what water levels respond to). They differ by the <strong>geoid height N</strong>: <strong>H = h &minus; N</strong>. In the conterminous U.S., N is negative (the geoid is below the ellipsoid), so orthometric heights are larger than ellipsoid heights. NGS geoid models (e.g., GEOID18) supply N.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000001', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'equation', '{"latex":"H = h - N","label":"Orthometric = ellipsoid height − geoid height","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000002', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'callout', '{"type":"info","text":"Memory hook: H = h − N. Orthometric height (H, what you survey to) equals GNSS ellipsoid height (h) minus the geoid undulation (N). In the U.S., N is negative, so H comes out larger than h."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000003', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'text', '{"html":"<h3>State Plane Coordinate Systems</h3><p>The <strong>State Plane Coordinate System (SPCS)</strong> maps the curved Earth onto a flat grid so surveyors can use plane coordinates (northing, easting) over a state-sized area while keeping distortion small (designed to about 1 part in 10,000). Two conformal projections are used: the <strong>Lambert Conformal Conic</strong> for zones that are wide east-west, and the <strong>Transverse Mercator</strong> for zones that are tall north-south. A state is divided into zones to bound the distortion.</p><p><strong>Texas</strong> uses the <strong>Lambert Conformal Conic</strong> projection (because the state is wider than it is tall) with <strong>five zones</strong>: North, North Central, Central, South Central, and South. Each zone has its own defining parallels and false origin. A surveyor working near a county line must confirm which zone applies, because coordinates are zone-specific.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000004', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'callout', '{"type":"warning","text":"Texas specifics: Texas SPCS uses the Lambert Conformal Conic projection in five zones (North, North Central, Central, South Central, South). A project straddling a zone boundary must state which zone its coordinates are in; values are not interchangeable between zones."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000005', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'text', '{"html":"<h3>Grid, ground, and the combined factor</h3><p>SPCS distances are <strong>grid distances</strong>, not the distances you measure on the ground. Two effects separate them. The <strong>grid scale factor (k)</strong> accounts for the projection (the grid is slightly short along the standard parallels and slightly long away from them). The <strong>elevation (sea-level) factor</strong> reduces a ground distance down to the ellipsoid, since a line at elevation is longer than its projection on the ellipsoid: elevation factor &asymp; R/(R + h), where R is the mean Earth radius (~20,906,000 ft).</p><p>Multiply them to get the <strong>combined factor</strong>. Then: <strong>grid distance = ground distance &times; combined factor</strong>, and inversely <strong>ground distance = grid distance &divide; combined factor</strong>. Mixing these up &mdash; or applying the factor in the wrong direction &mdash; is a frequent error. As a rule, ground distances are usually a little longer than grid distances.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000006', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'equation', '{"latex":"\\text{CF}=k\\cdot\\frac{R}{R+h},\\qquad D_{\\text{grid}}=D_{\\text{ground}}\\cdot\\text{CF},\\qquad D_{\\text{ground}}=\\frac{D_{\\text{grid}}}{\\text{CF}}","label":"Combined factor and grid/ground conversion","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000007', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'table', '{"headers":["Concept","Definition / use"],"rows":[["NAD83","Horizontal datum on the GRS80 ellipsoid; basis of geodetic lat/long and SPCS"],["NAVD88","Vertical datum; orthometric (geoid-referenced) heights"],["Geoid height N","Separation between geoid and ellipsoid; H = h − N"],["Grid scale factor k","Projection distortion of length at a point"],["Elevation factor","R/(R+h); reduces ground distance to the ellipsoid"],["Convergence (γ)","Angle between grid north and geodetic north; azimuth_grid = azimuth_geodetic − γ"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000008', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'text', '{"html":"<h3>North directions and convergence</h3><p>On a projection, <strong>grid north</strong> (the y-axis) and <strong>geodetic (true) north</strong> generally do not coincide except along the central meridian. Their difference is the <strong>convergence angle</strong> (or mapping angle), &gamma;. To convert a geodetic azimuth to a grid azimuth you apply convergence, and a small <strong>arc-to-chord (t&minus;T) correction</strong> may apply for long lines. For most FS questions, remember the relationship grid azimuth = geodetic azimuth &minus; convergence (with the sign depending on which side of the central meridian you are on), and keep <strong>three norths</strong> straight: magnetic, true/geodetic, and grid.</p>"}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0006-0000-0000-000000000009', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'key_takeaways', '{"title":"Key Takeaways","items":["NAD83 (GRS80 ellipsoid) is the horizontal datum; NAVD88 gives orthometric heights from the geoid.","H = h − N: orthometric = ellipsoid height − geoid height (N is negative in the U.S.).","Texas SPCS = Lambert Conformal Conic in five zones (N, NC, C, SC, S).","Combined factor = grid scale × elevation factor; ground = grid ÷ combined factor."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000000', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'text', '{"html":"<h3>Latitudes and departures</h3><p>A traverse is a connected series of courses, each with a direction and a distance. To compute coordinates, decompose every course into a north-south component (<strong>latitude</strong>) and an east-west component (<strong>departure</strong>). Using azimuth (clockwise from north): <strong>latitude = distance &middot; cos(azimuth)</strong> and <strong>departure = distance &middot; sin(azimuth)</strong>. The trig functions deliver the signs automatically when you use azimuths; with quadrant bearings you must assign the sign by quadrant.</p><p>Sign convention is the heart of the computation: <strong>north and east are positive; south and west are negative</strong>. A course running S&hairsp;W has a negative latitude and a negative departure. Getting a single sign wrong throws off every downstream coordinate, so verify each course''s quadrant against its computed signs.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000001', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'equation', '{"latex":"\\text{Lat}=D\\cos(\\text{Az}),\\qquad \\text{Dep}=D\\sin(\\text{Az})","label":"Latitude and departure of a course","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000002', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'table', '{"headers":["Quadrant / direction","Latitude sign","Departure sign"],"rows":[["NE","+ (north)","+ (east)"],["SE","− (south)","+ (east)"],["SW","− (south)","− (west)"],["NW","+ (north)","− (west)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000003', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'text', '{"html":"<h3>Misclosure and relative precision</h3><p>For a <strong>closed-loop</strong> traverse that returns to its start, the latitudes should sum to zero and the departures should sum to zero. They never quite do; the residual sums are the <strong>misclosure in latitude</strong> and <strong>misclosure in departure</strong>. The <strong>linear misclosure</strong> is their hypotenuse: sqrt((&Sigma;lat)&sup2; + (&Sigma;dep)&sup2;). (For a closed <em>connecting</em> traverse between two known points, compare the summed latitudes/departures to the known coordinate differences.)</p><p>The quality of the work is judged by <strong>relative precision</strong> (ratio of closure): the linear misclosure divided into the total perimeter, expressed as a ratio <strong>1 : (perimeter &divide; misclosure)</strong>. A result of 1:12,000 means the misclosure is one part in twelve thousand of the distance traversed. Compare against the standard required for the survey class (e.g., 1:5,000 for many boundary surveys, higher for control).</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000004', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'equation', '{"latex":"E=\\sqrt{\\left(\\textstyle\\sum\\text{Lat}\\right)^2+\\left(\\textstyle\\sum\\text{Dep}\\right)^2},\\qquad \\text{Precision}=1:\\frac{\\text{perimeter}}{E}","label":"Linear misclosure and relative precision","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000005', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'text', '{"html":"<h3>Adjusting with the compass (Bowditch) rule</h3><p>Once the misclosure is within tolerance, distribute it so the traverse closes perfectly. The most common method is the <strong>compass rule (Bowditch rule)</strong>, which assumes the precision of angles and distances is balanced and therefore distributes the misclosure to each course <strong>in proportion to that course''s length</strong>. For each course, the correction to its latitude is</p><p style=\"text-align:center\"><em>correction&hairsp;to&hairsp;latitude = &minus;(&Sigma;lat) &times; (course length &divide; perimeter)</em></p><p>with the analogous expression for departure using &Sigma;dep. The negative sign removes the accumulated misclosure. Apply the corrections, then accumulate the adjusted latitudes and departures from the starting coordinate to obtain the <strong>adjusted coordinates</strong> of each station. (The <strong>transit rule</strong> distributes in proportion to the latitude/departure magnitude instead; the <strong>least-squares</strong> adjustment is the rigorous method.)</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000006', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'equation', '{"latex":"\\delta\\text{Lat}_i=-\\left(\\textstyle\\sum\\text{Lat}\\right)\\frac{L_i}{\\sum L},\\qquad \\delta\\text{Dep}_i=-\\left(\\textstyle\\sum\\text{Dep}\\right)\\frac{L_i}{\\sum L}","label":"Compass (Bowditch) rule corrections","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000007', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A closed traverse — each course resolved into latitude (N-S) and departure (E-W), with the small misclosure vector closing the loop."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000008', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'callout', '{"type":"warning","text":"Exam trap: assign latitude/departure signs by quadrant (S and W are negative). Relative precision is perimeter ÷ misclosure, reported as 1:N — a larger N is better. The compass-rule correction is proportional to course length, the transit rule to lat/dep magnitude."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0007-0000-0000-000000000009', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'key_takeaways', '{"title":"Key Takeaways","items":["Lat = D·cos(Az), Dep = D·sin(Az); north/east +, south/west −.","Linear misclosure = hypot(Σlat, Σdep); loop sums should be zero.","Relative precision = 1 : (perimeter ÷ misclosure); bigger denominator = better.","Compass (Bowditch) rule spreads misclosure proportionally to course length to get adjusted coordinates."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000000', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'text', '{"html":"<h3>Area by coordinates (the shoelace method)</h3><p>When the corners of a parcel are known as coordinates, the <strong>shoelace (coordinate) method</strong> gives the area directly. Going around the polygon in order, cross-multiply each point''s coordinates with the next point''s, sum the differences, take the absolute value, and halve it:</p><p>The name comes from the criss-cross pattern of the multiplications. Take the <strong>absolute value</strong> (a clockwise traverse yields a negative raw sum) and remember the <strong>factor of one-half</strong> &mdash; forgetting it doubles the area. To report in acres, divide square feet by <strong>43,560</strong>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000001', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'equation', '{"latex":"A=\\tfrac12\\left|\\sum_{i=1}^{n}\\left(x_i\\,y_{i+1}-x_{i+1}\\,y_i\\right)\\right|","label":"Shoelace (coordinate) area","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000002', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'text', '{"html":"<h3>Area by double meridian distance (DMD)</h3><p>Before coordinates were universal, area was computed from <strong>latitudes and departures</strong> using the <strong>double-meridian-distance (DMD)</strong> method &mdash; still tested and still handy directly off an adjusted traverse. The <strong>DMD of a course</strong> equals the DMD of the previous course plus the departure of the previous course plus the departure of the present course. The first course''s DMD equals its own departure. Then the <strong>double area</strong> is the sum of (DMD &times; latitude) for all courses, and the area is half its absolute value.</p><p>The method is just the shoelace formula reorganized around a reference meridian, which is why both give the same answer. Use whichever the problem hands you: coordinates &rarr; shoelace; latitudes/departures &rarr; DMD.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000003', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'equation', '{"latex":"\\text{DMD}_i=\\text{DMD}_{i-1}+\\text{Dep}_{i-1}+\\text{Dep}_i,\\qquad A=\\tfrac12\\left|\\sum \\text{DMD}_i\\cdot\\text{Lat}_i\\right|","label":"Double-meridian-distance area","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000004', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'text', '{"html":"<h3>Irregular areas: trapezoidal and Simpson''s rules</h3><p>For an area bounded by an irregular line (a stream, a road edge) sampled by <strong>offsets</strong> at equal spacing d, two numerical rules apply. The <strong>trapezoidal rule</strong> treats each strip as a trapezoid: A = d&middot;[(h&#8320; + h&#8345;)/2 + (h&#8321; + h&#8322; + &hellip; + h&#8345;&#8331;&#8321;)] &mdash; half the two end offsets plus all the interior offsets, times the spacing.</p><p><strong>Simpson''s one-third rule</strong> fits parabolas through groups of points and is more accurate for curved boundaries, but it <strong>requires an even number of intervals</strong> (odd number of offsets): A = (d/3)&middot;[h&#8320; + h&#8345; + 4(odd-indexed offsets) + 2(even-indexed interior offsets)]. If you have an odd number of intervals, handle the last strip separately with the trapezoidal rule.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000005', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'equation', '{"latex":"A_{\\text{trap}}=d\\!\\left[\\frac{h_0+h_n}{2}+\\sum_{i=1}^{n-1}h_i\\right],\\quad A_{\\text{Simpson}}=\\frac{d}{3}\\!\\left[h_0+h_n+4\\!\\!\\sum_{\\text{odd}}\\!h_i+2\\!\\!\\sum_{\\text{even}}\\!h_i\\right]","label":"Trapezoidal and Simpson''s one-third rules","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000006', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'text', '{"html":"<h3>Volumes: average end area and prismoidal</h3><p>Earthwork volume between two cross-sections a distance L apart is estimated by the <strong>average-end-area method</strong>: V = L &middot; (A&#8321; + A&#8322;)/2, where A&#8321; and A&#8322; are the cross-sectional areas at the ends. It is simple and slightly overestimates volume for sections that taper. Divide cubic feet by <strong>27</strong> to get <strong>cubic yards</strong>, the standard earthwork unit.</p><p>The <strong>prismoidal formula</strong> is more accurate: V = (L/6)(A&#8321; + 4A&#8344; + A&#8322;), where A&#8344; is the area of the <em>middle</em> section (computed from averaged dimensions, not the average of the two end areas). The difference between the two methods is the <strong>prismoidal correction</strong>. For exam purposes: average-end-area is the default; reach for the prismoidal formula when the problem stresses accuracy or supplies a middle section.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000007', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'table', '{"headers":["Method","Formula","When to use"],"rows":[["Shoelace (coordinates)","A = ½|Σ(x_i y_{i+1} − x_{i+1} y_i)|","Corners given as coordinates"],["DMD","A = ½|Σ DMD·Lat|","Latitudes/departures from a traverse"],["Trapezoidal","A = d[(h0+hn)/2 + Σ interior]","Equally spaced offsets, any count"],["Simpson''s ⅓","A = (d/3)[ends + 4·odd + 2·even]","Curved boundary, even # of intervals"],["Average end area","V = L(A1 + A2)/2","Earthwork between cross-sections"],["Prismoidal","V = (L/6)(A1 + 4Am + A2)","When higher accuracy is required"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000008', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'callout', '{"type":"warning","text":"Exam trap: don''t forget the ½ in the shoelace/DMD area, take the absolute value, and convert ft²→acres by ÷43,560. Simpson''s ⅓ rule needs an EVEN number of intervals. Convert ft³→yd³ by ÷27, not ÷9."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0008-0000-0000-000000000009', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'key_takeaways', '{"title":"Key Takeaways","items":["Shoelace area A = ½|Σ(x_i y_{i+1} − x_{i+1} y_i)|; ÷43,560 for acres.","DMD area = ½|Σ(DMD·Lat)|; DMD_i = DMD_{i−1} + Dep_{i−1} + Dep_i.","Trapezoidal rule for any offset count; Simpson''s ⅓ needs an even number of intervals.","Volume: average end area V = L(A1+A2)/2 (÷27 for cubic yards); prismoidal is more accurate."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000000', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'text', '{"html":"<h3>How GNSS computes a position</h3><p><strong>GNSS</strong> (the umbrella term for GPS, GLONASS, Galileo, BeiDou) positions a receiver by <strong>trilateration</strong>: each satellite broadcasts its position and time, the receiver measures the travel time of the signal to compute a <strong>range</strong>, and the intersection of ranges from several satellites fixes the receiver''s location. Because the receiver''s inexpensive clock is not perfectly synchronized with the satellites'' atomic clocks, every measured range contains a common <strong>clock-bias error</strong> &mdash; hence the term <em>pseudorange</em>.</p><p>That clock bias is a fourth unknown alongside the three position coordinates (X, Y, Z). Therefore a 3-D fix requires a <strong>minimum of four satellites</strong>: three for position and one to solve the receiver-clock offset. More satellites add redundancy and improve the solution.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000001', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'callout', '{"type":"info","text":"Why four satellites? Three unknowns of position (X, Y, Z) plus one receiver-clock bias = four unknowns, so four pseudorange equations are the minimum for a 3-D position fix."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000002', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'text', '{"html":"<h3>Code vs. carrier-phase observations</h3><p>Receivers can measure range two ways. The <strong>code (pseudorange)</strong> observable matches the satellite''s broadcast code to a receiver-generated replica; it is robust and instantaneous but only <strong>meter-level</strong> accurate &mdash; fine for navigation, not for surveying. The <strong>carrier-phase</strong> observable measures the phase of the underlying carrier wave (wavelength ~19&ndash;24 cm), which is far finer &mdash; <strong>centimeter to millimeter</strong> level &mdash; but introduces the <strong>integer ambiguity</strong>: the receiver knows the fractional phase but not the whole number of cycles to the satellite. Surveying-grade positioning depends on <strong>resolving that ambiguity</strong> (&ldquo;fixing&rdquo; the solution).</p><p>Carrier-phase processing is what makes GNSS a surveying tool. A &ldquo;float&rdquo; solution (ambiguity unresolved) is decimeter-level; a &ldquo;fixed&rdquo; solution (ambiguity resolved) is centimeter-level. Most precision methods &mdash; static and RTK alike &mdash; rely on carrier phase and differencing between receivers to cancel common errors.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000003', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'table', '{"headers":["Method","Mode","Typical accuracy"],"rows":[["Autonomous (code)","Single receiver, real-time","~1–3 m"],["DGPS / SBAS (code, corrected)","Differential corrections","sub-meter"],["RTK / Network RTK (carrier)","Real-time, base + rover or network","1–3 cm"],["Static (carrier, post-processed)","Long occupation, processed later","mm–cm (highest)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000004', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'text', '{"html":"<h3>Positioning methods compared</h3><p>The methods trade accuracy against speed and convenience:</p><ul><li><strong>Autonomous:</strong> a single receiver using code; a few meters &mdash; navigation only.</li><li><strong>DGPS/SBAS:</strong> code with differential corrections; sub-meter &mdash; GIS and mapping.</li><li><strong>RTK (real-time kinematic):</strong> carrier phase with a base station (or a <strong>network RTK</strong>/RTN service) streaming corrections to the rover; <strong>real-time centimeter</strong> accuracy &mdash; the workhorse of field surveying.</li><li><strong>Static:</strong> long simultaneous occupations on two or more points, carrier-phase data <strong>post-processed</strong>; the <strong>highest accuracy</strong> &mdash; control and geodetic work. (Rapid-static and PPP are variants.)</li></ul><p>Choose by the job: control points and long baselines favor static; production topographic and stakeout work favor RTK; reconnaissance and GIS favor DGPS.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000005', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'text', '{"html":"<h3>Error sources and satellite geometry (DOP)</h3><p>GNSS accuracy is limited by predictable error sources: <strong>ionospheric</strong> and <strong>tropospheric</strong> delay (the atmosphere slows the signal), <strong>satellite orbit and clock</strong> errors, and <strong>multipath</strong> (signals reflecting off nearby surfaces before reaching the antenna). Differential techniques cancel the errors common to two nearby receivers (atmosphere, orbit, satellite clock); multipath is site-specific and is fought with good antennas and clear sky.</p><p>Beyond the ranging errors, the <strong>geometry</strong> of the visible satellites matters. <strong>Dilution of precision (DOP)</strong> quantifies how satellite spread amplifies range error into position error. Satellites bunched together give a <strong>high DOP</strong> (poor geometry, larger error); satellites well-distributed across the sky give a <strong>low DOP</strong> (better). A low PDOP/GDOP is a precondition for a reliable fix &mdash; the same ranging precision yields a much better position when the geometry is strong.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000006', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'callout', '{"type":"warning","text":"Exam trap: a LOWER DOP is better (good geometry). Four satellites is the minimum for 3-D because the receiver clock bias is a fourth unknown. Code = meter-level; carrier phase (ambiguity resolved) = centimeter-level."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0009-0000-0000-000000000007', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'key_takeaways', '{"title":"Key Takeaways","items":["GNSS trilaterates from pseudoranges; 4 satellites minimum (3 position unknowns + receiver clock bias).","Code is meter-level; carrier phase with resolved integer ambiguity is centimeter-level.","Static (post-processed) = highest accuracy; RTK/network RTK = real-time centimeter; DGPS = sub-meter.","Errors: ionosphere, troposphere, orbit/clock, multipath; lower DOP (better geometry) = better accuracy."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0010-0000-0000-000000000000', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'text', '{"html":"<h3>How to use this problem set</h3><p>This final lesson is <strong>practice, not new theory</strong>. The accompanying randomized <strong>problem templates</strong> regenerate fresh numbers each attempt, spanning the computational core of the FS: right-triangle/Pythagorean geometry, bearing-to-azimuth conversion, latitude/departure, traverse misclosure, area by coordinates, an EDM/temperature correction, and a horizontal-curve tangent. Work them repeatedly until each becomes automatic.</p><p>Adopt a consistent <strong>five-step routine</strong> for every problem: (1) identify the <em>unknown and its unit</em>; (2) choose the <em>formula</em>; (3) check <em>signs, quadrant, and angle mode</em>; (4) <em>estimate</em> the magnitude; (5) <em>compute and convert</em>. The estimate step alone catches most blunders &mdash; if your hypotenuse is shorter than a leg, or your traverse misclosure is larger than a course, stop and recheck.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0010-0000-0000-000000000001', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'accordion', '{"sections":[{"title":"Worked example 1 — Slope to horizontal","content":"<p>A total station reads a slope distance of 642.18 ft at a zenith angle of 86&deg;30&prime;. Find the horizontal distance.</p><p><strong>Solution.</strong> Zenith angle &rarr; use H = S&middot;sin&hairsp;z. Convert 86&deg;30&prime; = 86.5&deg;. sin(86.5&deg;) = 0.99813. H = 642.18 &times; 0.99813 = <strong>641.0 ft</strong>. Check: the sight is nearly level, so H should be just under S &mdash; it is.</p>","open":false},{"title":"Worked example 2 — Bearing to azimuth","content":"<p>Convert the bearing S 47&deg;15&prime; W to an azimuth.</p><p><strong>Solution.</strong> SW quadrant &rarr; Az = 180&deg; + bearing angle. 47&deg;15&prime; = 47.25&deg;. Az = 180&deg; + 47.25&deg; = <strong>227.25&deg;</strong> (227&deg;15&prime;). Check: a southwest line must have an azimuth between 180&deg; and 270&deg; &mdash; it does.</p>","open":false},{"title":"Worked example 3 — Traverse misclosure & precision","content":"<p>A closed traverse with a 2,480-ft perimeter has &Sigma;latitudes = +0.06 ft and &Sigma;departures = &minus;0.08 ft. Find the linear misclosure and relative precision.</p><p><strong>Solution.</strong> E = sqrt(0.06&sup2; + 0.08&sup2;) = sqrt(0.0036 + 0.0064) = sqrt(0.01) = <strong>0.10 ft</strong>. Precision = 2,480 &divide; 0.10 = 24,800, i.e., <strong>1:24,800</strong> &mdash; well within typical boundary tolerance.</p>","open":false},{"title":"Worked example 4 — Area by coordinates","content":"<p>A triangle has corners A(0,0), B(400,0), C(400,300) ft. Find the area in acres.</p><p><strong>Solution.</strong> Shoelace: 2A = |x_A(y_B&minus;y_C) + x_B(y_C&minus;y_A) + x_C(y_A&minus;y_B)| = |0(0&minus;300) + 400(300&minus;0) + 400(0&minus;0)| = 120,000. A = 60,000 ft&sup2;. In acres: 60,000 &divide; 43,560 = <strong>1.377 ac</strong>.</p>","open":false},{"title":"Worked example 5 — Horizontal curve tangent","content":"<p>A simple curve has R = 800 ft and intersection angle I = 36&deg;. Find the tangent length T.</p><p><strong>Solution.</strong> T = R&middot;tan(I/2) = 800 &times; tan(18&deg;) = 800 &times; 0.32492 = <strong>259.9 ft</strong>. Don''t forget to halve I before taking the tangent.</p>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0010-0000-0000-000000000002', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'text', '{"html":"<h3>Pace and self-check</h3><p>On the real exam you have roughly <strong>2.9 minutes per question</strong>. Practice to a comfortable margin below that so you can afford to recheck. When you finish a computation, run the three fastest checks: <strong>unit</strong> (did the answer come out in the requested unit?), <strong>sign/quadrant</strong> (is the direction or component plausible?), and <strong>magnitude</strong> (does the size make physical sense?). These three catch the overwhelming majority of avoidable errors.</p><p>Treat each randomized template below as a timed drill. Re-run it until you can reach the correct value, in the correct unit, in under two minutes without notes. That fluency &mdash; not memorized trivia &mdash; is what passes the FS.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0010-0000-0000-000000000003', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'callout', '{"type":"success","text":"Final checklist before you submit any answer: (1) degree mode on; (2) right formula form; (3) correct sign/quadrant; (4) unit converted (ft↔m, ft²↔acres, ft³↔yd³); (5) magnitude sanity-checked against an estimate."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2510-0010-0000-0000-000000000004', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'key_takeaways', '{"title":"Key Takeaways","items":["Apply the five-step routine: unknown/unit → formula → signs/quadrant/mode → estimate → compute/convert.","Drill the randomized templates (Pythagorean, bearing↔azimuth, lat/dep, misclosure, area, EDM/temp, curve) to fluency.","Self-check every answer for unit, sign/quadrant, and magnitude.","Budget ~2.9 min/question; speed plus the checklist beats memorized trivia."]}'::jsonb, 4);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000001', 'Fundamentals of Surveying (FS) exam', 'The NCEES computer-based, multiple-choice exam that, with the education requirement, qualifies a candidate for the Surveyor-in-Training (SIT) credential; closed-book except for the searchable NCEES FS Reference Handbook.', 'It is the entry exam, not the PS exam.', 'c1000019-0000-0000-0000-000000000019', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000002', 'Surveyor-in-Training (SIT)', 'The Texas entry-level surveying credential, earned by passing the FS exam and meeting the education requirement; the SIT accrues qualifying experience under an RPLS toward full licensure.', NULL, 'c1000019-0000-0000-0000-000000000019', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000003', 'NCEES FS Reference Handbook', 'The only reference allowed during the FS exam — a searchable on-screen document containing the formulas, constants, and tables used on the test.', NULL, 'c1000019-0000-0000-0000-000000000019', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000004', 'Law of cosines', 'For any triangle, c² = a² + b² − 2ab·cos C — used to find the third side from two sides and the included angle (SAS), or an angle from three sides (SSS).', NULL, 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000005', 'Inverse computation', 'Computing the distance and azimuth between two known coordinate points: distance = hypot(ΔE, ΔN); azimuth = atan2(ΔE, ΔN) reduced to 0–360°.', NULL, 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000006', 'US survey foot vs. international foot', '1 international ft = 0.3048 m exactly; 1 US survey ft = 1200/3937 m. They differ by about 2 ppm — negligible for short distances but significant over State Plane coordinates.', NULL, 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000007', 'atan2', 'The two-argument arctangent that returns an angle in the correct quadrant; in surveying, azimuth = atan2(ΔE, ΔN), avoiding the quadrant ambiguity of a single-argument arctangent.', NULL, 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000008', 'Systematic vs. random error', 'Systematic errors follow a physical law, accumulate in one direction, and can be corrected/calibrated out; random errors are small unavoidable fluctuations of either sign that follow the normal distribution and are treated statistically.', NULL, 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000009', 'Accuracy vs. precision', 'Accuracy is closeness to the true value (reflects bias/systematic error); precision is repeatability/agreement of repeated measurements (reflects scatter/random error).', NULL, 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000010', 'Standard deviation of the mean', 'σ_m = σ/sqrt(n): the spread of the sample mean, which improves as the square root of the number of observations — the basis for taking redundant measurements.', NULL, 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000011', 'Error propagation (sum)', 'For independent quantities added or subtracted, the combined error is the root-sum-square: E = sqrt(E1² + E2² + … ) — errors add in quadrature, not linearly.', NULL, 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000012', 'Zenith angle vs. vertical angle', 'A zenith angle is measured down from the vertical (a level sight = 90°), so H = S·sin z; a vertical (slope) angle is measured from horizontal (level = 0°), so H = S·cos α. The two are complements.', NULL, 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000013', 'Steel-tape temperature correction', 'Ct = α(T − T0)L, with α = 0.00000645/°F for steel and T0 = 68°F standard; a tape hotter than standard is longer, so the correction is positive (added).', NULL, 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000014', 'Quadrant-to-azimuth conversion', 'NE: Az = β; SE: Az = 180° − β; SW: Az = 180° + β; NW: Az = 360° − β, where β is the bearing''s acute angle. Azimuths run 0–360° clockwise from north.', NULL, 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000015', 'Angular misclosure condition', 'For a closed-loop traverse, the interior angles must sum to (n − 2)·180°; the difference from the measured sum is the angular misclosure, distributed equally as misclosure ÷ n per angle.', NULL, 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000016', 'Height of instrument (HI)', 'The elevation of the level''s line of sight: HI = (known point elevation) + backsight. New point elevations are HI − foresight.', NULL, 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000017', 'Backsight vs. foresight', 'A backsight (plus sight) is read on a point of known elevation and added to get HI; a foresight (minus sight) is read on a point of unknown elevation and subtracted from HI to get its elevation.', NULL, 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000018', 'Turning point (TP)', 'A stable temporary point on which the rod stays fixed while the instrument is moved ahead; it receives a foresight and then a backsight, carrying the line of levels forward.', NULL, 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000019', 'Balancing sight distances', 'Making backsight and foresight distances equal at each setup so collimation, earth-curvature, and refraction errors affect both readings equally and cancel in the elevation difference.', NULL, 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000020', 'NAD83 vs. NAVD88', 'NAD83 is the horizontal datum (geodetic positions on the GRS80 ellipsoid); NAVD88 is the vertical datum (orthometric heights referenced to the geoid).', NULL, 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000021', 'Geoid undulation (N) / H = h − N', 'N is the separation between the geoid and the ellipsoid; orthometric height H equals GNSS ellipsoid height h minus N. In the conterminous U.S. N is negative, so H > h.', NULL, 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000022', 'Texas State Plane (Lambert, five zones)', 'The Texas SPCS uses the Lambert Conformal Conic projection divided into five zones — North, North Central, Central, South Central, and South — each with its own defining parallels.', NULL, 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000023', 'Combined factor', 'The product of the grid scale factor and the elevation (sea-level) factor; grid distance = ground distance × combined factor, and ground distance = grid distance ÷ combined factor.', NULL, 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000024', 'Latitude and departure', 'The north-south (latitude = D·cos Az) and east-west (departure = D·sin Az) components of a traverse course; north/east are positive, south/west negative.', NULL, 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000025', 'Linear misclosure', 'The closure error of a traverse: sqrt((Σlatitudes)² + (Σdepartures)²). For a closed loop the latitude and departure sums should each be zero.', NULL, 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000026', 'Relative precision (ratio of closure)', 'The traverse misclosure expressed as a fraction of the perimeter: 1 : (perimeter ÷ misclosure). A larger denominator (e.g., 1:15,000 vs. 1:5,000) indicates better work.', NULL, 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000027', 'Compass (Bowditch) rule', 'A traverse adjustment that distributes the latitude and departure misclosure to each course in proportion to the course''s length, assuming balanced angular and linear precision.', NULL, 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000028', 'Shoelace (coordinate) area', 'A = ½·|Σ(x_i·y_{i+1} − x_{i+1}·y_i)| computed around the polygon; take the absolute value and divide ft² by 43,560 to get acres.', NULL, 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000029', 'Double meridian distance (DMD)', 'A course''s DMD = previous DMD + previous departure + present departure (first = its own departure); area = ½|Σ(DMD × latitude)|.', NULL, 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000030', 'Simpson''s one-third rule', 'A numerical area rule, A = (d/3)[ends + 4·(odd offsets) + 2·(even interior offsets)], that fits parabolas and requires an even number of equal intervals.', NULL, 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000031', 'Average-end-area volume', 'V = L·(A1 + A2)/2 — the volume of earthwork between two cross-sections of areas A1 and A2 a distance L apart; divide ft³ by 27 for cubic yards.', NULL, 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000032', 'Why four satellites (pseudorange)', 'A 3-D GNSS fix has four unknowns — three position coordinates plus the receiver-clock bias — so a minimum of four satellite pseudorange measurements is required.', NULL, 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000033', 'Carrier phase vs. code', 'Code (pseudorange) positioning is meter-level and instantaneous; carrier-phase positioning is centimeter-level but requires resolving the integer ambiguity (the unknown whole number of carrier cycles).', NULL, 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000034', 'RTK vs. static GNSS', 'RTK gives real-time centimeter accuracy using a base/network correction stream; static occupies points for an extended time and post-processes carrier-phase data for the highest accuracy (control/geodetic work).', NULL, 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000035', 'Dilution of precision (DOP)', 'A measure of how satellite geometry amplifies ranging error into position error; well-spread satellites give a low DOP (good), bunched satellites a high DOP (poor).', NULL, 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000036', 'Five-step problem routine', 'Identify the unknown and its unit → choose the formula → check signs/quadrant/angle mode → estimate the magnitude → compute and convert. The estimate step catches most blunders.', NULL, 'c1000019-0000-0000-0000-000000000019', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000037', 'FS pacing', 'About 2.9 minutes per question (~110 questions in ~5h20m). Bank time on routine computations to fund harder conceptual items and to allow rechecking.', NULL, 'c1000019-0000-0000-0000-000000000019', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2540-0000-0000-0000-000000000038', 'Three-point answer check', 'Before accepting any answer, verify the unit (is it what was asked?), the sign/quadrant (is the direction plausible?), and the magnitude (does the size make physical sense?).', NULL, 'c1000019-0000-0000-0000-000000000019', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', 'surveying', ARRAY['buildout','module-25']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000001', 'During the NCEES Fundamentals of Surveying (FS) exam, which reference may a candidate use?', 'multiple_choice', '["Any textbook the candidate brings","Only the searchable NCEES FS Reference Handbook provided on-screen","No reference at all","The candidate''s own printed formula sheet"]'::jsonb, 'Only the searchable NCEES FS Reference Handbook provided on-screen', 'The FS is closed-book except for the on-screen, searchable NCEES FS Reference Handbook. Personal textbooks or notes are not permitted, but it is not a no-reference exam.', 'easy', 'c1000019-0000-0000-0000-000000000019', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000002', 'Passing the FS exam, together with the education requirement, qualifies a Texas candidate for which credential?', 'multiple_choice', '["Registered Professional Land Surveyor (RPLS)","Licensed State Land Surveyor (LSLS)","Surveyor-in-Training (SIT)","Certified Federal Surveyor (CFedS)"]'::jsonb, 'Surveyor-in-Training (SIT)', 'The FS is the entry exam leading to the SIT. The RPLS requires further experience plus the PS and Texas exams; the LSLS is an additional state-land credential.', 'easy', 'c1000019-0000-0000-0000-000000000019', '153e57a7-df0b-4b30-a4e8-cbfe125785ec', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000003', 'In the inverse computation between two coordinate points, the azimuth is best computed as:', 'multiple_choice', '["atan(ΔN/ΔE)","atan2(ΔE, ΔN), reduced to 0–360°","atan2(ΔN, ΔE), reduced to 0–360°","asin(ΔE/distance)"]'::jsonb, 'atan2(ΔE, ΔN), reduced to 0–360°', 'Azimuth is measured clockwise from north, so it is atan2(easting difference, northing difference). The two-argument arctangent resolves the quadrant; reduce a negative result by adding 360°.', 'medium', 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000004', 'Convert the bearing N 35°30'' E to its decimal-degree azimuth.', 'numeric_input', '[]'::jsonb, '35.5', 'For a northeast bearing, the azimuth equals the bearing angle directly: 35°30'' = 35.5°.', 'easy', 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000005', 'How many square feet are in one acre?', 'numeric_input', '[]'::jsonb, '43560', 'One acre equals 43,560 square feet (equivalently 10 square chains).', 'easy', 'c1000019-0000-0000-0000-000000000019', '74470d18-37e1-4928-a697-46927b811835', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000006', 'A steel tape that is consistently 0.02 ft too long produces which kind of error?', 'multiple_choice', '["Random error","Systematic error","A mistake (blunder)","No error, because it is constant"]'::jsonb, 'Systematic error', 'A constant, one-directional effect from a mis-standardized tape is a systematic error; it can be modeled and corrected. Random errors vary in sign; blunders are gross human mistakes.', 'easy', 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000007', 'Which statement correctly distinguishes accuracy from precision?', 'multiple_choice', '["Accuracy is repeatability; precision is closeness to the true value","Accuracy is closeness to the true value; precision is repeatability of measurements","They are the same thing","Precision improves only by removing systematic error"]'::jsonb, 'Accuracy is closeness to the true value; precision is repeatability of measurements', 'Accuracy reflects bias (closeness to truth); precision reflects scatter (agreement of repeated measurements). Averaging improves the mean''s precision but cannot remove a systematic bias.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000008', 'Two independent distances are measured with standard errors of 0.03 ft and 0.04 ft. The standard error of their sum is:', 'numeric_input', '[]'::jsonb, '0.05', 'Errors of a sum combine in quadrature: sqrt(0.03² + 0.04²) = sqrt(0.0009 + 0.0016) = sqrt(0.0025) = 0.05 ft.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'fb89ec38-209b-4125-9acf-7de4d88465bc', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000009', 'A total station measures a slope distance of 500.00 ft at a zenith angle of 90°. The horizontal distance is:', 'numeric_input', '[]'::jsonb, '500', 'For a zenith angle, H = S·sin z. At z = 90° (a level sight), sin 90° = 1, so H = 500.00 ft.', 'easy', 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000010', 'Convert the quadrant bearing S 20° E to an azimuth (degrees).', 'numeric_input', '[]'::jsonb, '160', 'For a southeast bearing, azimuth = 180° − bearing angle = 180° − 20° = 160°.', 'easy', 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000011', 'The interior angles of a closed five-sided (pentagon) traverse should sum to:', 'numeric_input', '[]'::jsonb, '540', 'Sum of interior angles = (n − 2)·180° = (5 − 2)·180° = 540°.', 'medium', 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000012', 'The sag correction for an unsupported steel tape is always:', 'multiple_choice', '["Positive (added), because sag lengthens the tape","Negative (subtracted), because the sagging tape reads too long","Zero, because tension cancels it","Positive at low tension and negative at high tension"]'::jsonb, 'Negative (subtracted), because the sagging tape reads too long', 'A tape supported only at its ends hangs in a catenary, so the distance read along the tape exceeds the chord. The correction is always negative.', 'medium', 'c1000019-0000-0000-0000-000000000019', '6e515c6d-3835-4681-84ca-7ce2215b7c28', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000013', 'In the height-of-instrument method, a backsight reading is:', 'multiple_choice', '["Subtracted from the known elevation to get HI","Added to the known elevation to get the height of instrument (HI)","Always taken on a point of unknown elevation","An intermediate side shot only"]'::jsonb, 'Added to the known elevation to get the height of instrument (HI)', 'A backsight is a plus sight read on a point of known elevation: HI = known elevation + BS. Foresights are subtracted to obtain new elevations.', 'easy', 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000014', 'A benchmark of elevation 412.50 ft is sighted with a backsight of 5.42 ft; a foresight of 7.10 ft is then read on a turning point. The TP elevation is (ft):', 'numeric_input', '[]'::jsonb, '410.82', 'HI = 412.50 + 5.42 = 417.92 ft; TP elevation = HI − FS = 417.92 − 7.10 = 410.82 ft.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000015', 'Making backsight and foresight distances equal at each setup primarily cancels which errors?', 'multiple_choice', '["Rod settlement and reading mistakes","Collimation, earth curvature, and refraction","Temperature and tension errors","Multipath and ionospheric delay"]'::jsonb, 'Collimation, earth curvature, and refraction', 'Balancing sight distances makes these distance-dependent systematic errors affect both the backsight and foresight equally, so they cancel in the elevation difference.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'b546fea7-83b5-4940-a51b-f02529e30b46', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000016', 'Given a GNSS ellipsoid height h and a geoid height N, the orthometric height H is:', 'multiple_choice', '["H = h + N","H = h − N","H = N − h","H = h × N"]'::jsonb, 'H = h − N', 'Orthometric height equals ellipsoid height minus the geoid height: H = h − N. In the conterminous U.S., N is negative, so H comes out larger than h.', 'medium', 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000017', 'The Texas State Plane Coordinate System uses which projection and how many zones?', 'multiple_choice', '["Transverse Mercator, two zones","Lambert Conformal Conic, five zones","Oblique Mercator, three zones","Lambert Conformal Conic, two zones"]'::jsonb, 'Lambert Conformal Conic, five zones', 'Because Texas is wider east-west than north-south, its SPCS uses the Lambert Conformal Conic projection, divided into five zones: North, North Central, Central, South Central, and South.', 'medium', 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000018', 'To obtain ground distance from a State Plane grid distance, you should:', 'multiple_choice', '["Multiply the grid distance by the combined factor","Divide the grid distance by the combined factor","Add the geoid height","Multiply by the grid scale factor only"]'::jsonb, 'Divide the grid distance by the combined factor', 'Grid distance = ground distance × combined factor, so ground distance = grid distance ÷ combined factor (the product of grid scale factor and elevation factor).', 'hard', 'c1000019-0000-0000-0000-000000000019', '0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000019', 'A traverse course runs S 50° W. The signs of its latitude and departure are:', 'multiple_choice', '["Latitude +, departure +","Latitude −, departure −","Latitude −, departure +","Latitude +, departure −"]'::jsonb, 'Latitude −, departure −', 'South gives a negative latitude and west gives a negative departure, so both components are negative in the SW quadrant.', 'easy', 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000020', 'A closed traverse with perimeter 3,000 ft has a linear misclosure of 0.15 ft. Its relative precision is approximately 1:N, where N is:', 'numeric_input', '[]'::jsonb, '20000', 'Relative precision = perimeter ÷ misclosure = 3,000 ÷ 0.15 = 20,000, i.e., 1:20,000.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000021', 'The compass (Bowditch) rule distributes traverse misclosure to each course in proportion to:', 'multiple_choice', '["The latitude and departure magnitudes of the course","The length of the course","The number of courses, equally","The interior angle at the course''s start"]'::jsonb, 'The length of the course', 'The compass rule corrects each course in proportion to its length. Distributing in proportion to latitude/departure magnitude is the transit rule.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'abf146f7-f77e-4d6c-a065-6de160ac604b', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000022', 'A rectangular parcel measures 300 ft by 200 ft. Its area in acres is (to two decimals):', 'numeric_input', '[]'::jsonb, '1.38', 'Area = 300 × 200 = 60,000 ft²; 60,000 ÷ 43,560 = 1.377 ≈ 1.38 acres.', 'easy', 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000023', 'Simpson''s one-third rule for area requires:', 'multiple_choice', '["An odd number of intervals","An even number of intervals (odd number of offsets)","Unequal offset spacing","Exactly three offsets"]'::jsonb, 'An even number of intervals (odd number of offsets)', 'Simpson''s one-third rule fits parabolas across pairs of intervals, so it needs an even number of equal intervals (an odd number of offsets). A leftover odd interval is handled by the trapezoidal rule.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000024', 'Two cross-sections of areas 120 ft² and 160 ft² are 50 ft apart. By average end area, the volume in cubic yards is:', 'numeric_input', '[]'::jsonb, '259.26', 'V = L(A1 + A2)/2 = 50 × (120 + 160)/2 = 50 × 140 = 7,000 ft³; 7,000 ÷ 27 = 259.26 yd³.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'e079ffe6-6bd0-499c-a406-a86b351ad5c2', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000025', 'Why does a GNSS receiver require a minimum of four satellites for a 3-D position?', 'multiple_choice', '["To average out multipath at four angles","Three for position plus one to solve the receiver-clock bias","One satellite per constellation is required","Four are needed only for RTK, not static"]'::jsonb, 'Three for position plus one to solve the receiver-clock bias', 'There are four unknowns — three position coordinates and the receiver clock offset — so four pseudorange equations (satellites) are the minimum.', 'medium', 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000026', 'Which GNSS observable is required to achieve centimeter-level surveying accuracy?', 'multiple_choice', '["Code (pseudorange) only","Carrier-phase with resolved integer ambiguity","The navigation message timestamp","Doppler measurement only"]'::jsonb, 'Carrier-phase with resolved integer ambiguity', 'Code positioning is meter-level. Centimeter accuracy requires carrier-phase observations with the integer ambiguity resolved (a ''fixed'' solution).', 'medium', 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000027', 'Regarding dilution of precision (DOP), a lower DOP value indicates better positioning geometry.', 'true_false', '["True","False"]'::jsonb, 'True', 'DOP measures how satellite geometry amplifies ranging error into position error; a lower DOP means well-distributed satellites and a better (more accurate) position.', 'easy', 'c1000019-0000-0000-0000-000000000019', '249bd04d-b9d0-455d-b416-023af3efc6b4', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000028', 'A simple horizontal curve has R = 600 ft and intersection angle I = 40°. Compute the tangent length T (ft).', 'numeric_input', '[]'::jsonb, '218.38', 'T = R·tan(I/2) = 600 × tan(20°) = 600 × 0.36397 = 218.38 ft. Remember to halve I before taking the tangent.', 'medium', 'c1000019-0000-0000-0000-000000000019', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2530-0000-0000-0000-000000000029', 'A right triangle has legs of 90 ft and 120 ft. The hypotenuse is (ft):', 'numeric_input', '[]'::jsonb, '150', 'c = sqrt(90² + 120²) = sqrt(8,100 + 14,400) = sqrt(22,500) = 150 ft (a 3-4-5 triangle scaled by 30).', 'easy', 'c1000019-0000-0000-0000-000000000019', 'cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97', ARRAY['buildout','module-25']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000001', 'A right triangle has legs measuring {{a:f2}} ft and {{b:f2}} ft. Using the Pythagorean theorem, what is the length of the hypotenuse, in feet?', 'numeric_input', '[]'::jsonb, '0', 'By the Pythagorean theorem, c = sqrt(a^2 + b^2) = sqrt({{a:f2}}^2 + {{b:f2}}^2) = {{_answer}} ft. The hypotenuse is always longer than either leg.', 'easy', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000002', 'A line has the quadrant bearing S {{b:dms}} E (south-and-east). Compute the AZIMUTH of the line (clockwise from north), in decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'A southeast bearing converts to azimuth with azimuth = 180 - bearing angle = 180 - {{b:f2}} = {{_answer}} deg.', 'easy', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000002', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000003', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the LATITUDE (north-south component) of this course, in feet.', 'numeric_input', '[]'::jsonb, '0', 'Latitude = d cos(alpha) = {{dist:f2}} x cos({{ang:f0}} deg) = {{_answer}} ft north. (Its departure, d sin(alpha), would be {{dep:f2}} ft east.)', 'medium', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000004', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE, in feet.', 'numeric_input', '[]'::jsonb, '0', 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'medium', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000004', 0.002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000005', 'A closed four-sided parcel has corner coordinates (X, Y), in feet, of A(0, 0), B({{xb}}, 0), C({{xb}}, {{yc}}), and D(0, {{yd}}), taken counter-clockwise. Using the coordinate (shoelace) method, what is the parcel area in ACRES? (1 acre = 43,560 sq ft.)', 'numeric_input', '[]'::jsonb, '0', 'The shoelace method yields a double area of {{xb}}*{{yc}} + {{xb}}*{{yd}}; halving gives {{areaSqFt:f1}} sq ft, which is {{areaSqFt:f1}} / 43,560 = {{_answer}} acres.', 'medium', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000005', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000006', 'A distance of {{L:f2}} ft is taped with a steel tape standardized at 68 degF. The field temperature is {{T:f1}} degF. Using alpha = 0.00000645 per degF, compute the TEMPERATURE CORRECTION (in feet) to be applied to the measured distance (give the signed value).', 'numeric_input', '[]'::jsonb, '0', 'Ct = alpha (T - T0) L = 0.00000645 x ({{T:f1}} - 68) x {{L:f2}} = 0.00000645 x {{dT:f1}} x {{L:f2}} = {{_answer}} ft. A positive value means the tape was hotter than standard (longer), so the correction is added.', 'medium', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000006', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2560-0000-0000-0000-000000000007', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}} degrees. What is the tangent length T (ft) from the PC to the PI?', 'numeric_input', '[]'::jsonb, '0', 'The tangent distance from the PC to the PI of a simple curve is T = R*tan(I/2) = {{R}} x tan({{I}} deg / 2) = {{_answer}} ft. Remember to halve I before taking the tangent.', 'medium', 'c1000019-0000-0000-0000-000000000019', NULL, ARRAY['buildout','module-25','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2550-0000-0000-0000-000000000007', 0.1);
