-- 356_buildout_m25.sql (GENERATED) — fill empty lessons for "SIT Exam Review — Fundamentals"
-- Module c1000019-0000-0000-0000-000000000019. Namespaced by tag 'buildout' / created_by 'buildout:m25' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c1000019-0000-0000-0000-000000000019' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c1000019-0000-0000-0000-000000000019' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000019-0000-0000-0000-000000000019' AND created_by='buildout:m25';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['Passing the NCEES Fundamentals of Surveying (FS) exam is the gateway to the Texas Surveyor-in-Training (SIT) credential.','The FS is computer-based, multiple-choice, closed-book except for the searchable NCEES FS Reference Handbook.','Heaviest topics are math/units, measurements/errors, distance/angles, leveling, traverse/coordinates, area, and GNSS.','Most lost points are avoidable: wrong calculator angle mode, unit mismatches, and sign errors on latitudes/departures.']::text[], learning_objectives=ARRAY['Describe the structure of the NCEES Fundamentals of Surveying (FS) exam and how passing it leads to the Texas SIT credential.','List the major topic areas the FS exam covers and their approximate weighting.','Apply a high-yield study and test-taking strategy, including unit awareness and use of the reference handbook.','Identify common avoidable mistakes (unit slips, calculator mode, sign errors) and how to prevent them.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='153e57a7-df0b-4b30-a4e8-cbfe125785ec';
DELETE FROM lesson_blocks WHERE lesson_id='153e57a7-df0b-4b30-a4e8-cbfe125785ec';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Right triangle: c = sqrt(a^2 + b^2); SOH-CAH-TOA relates sides and angles.','Oblique triangles: law of sines a/sin A = b/sin B; law of cosines c^2 = a^2 + b^2 − 2ab·cos C.','1 ft = 0.3048 m (intl); 1 acre = 43,560 ft²; 1 deg = 60'' = 3600"; radians = degrees × π/180.','Inverse between points: distance = hypot(ΔE, ΔN); azimuth = atan2(ΔE, ΔN) reduced to 0–360°.']::text[], learning_objectives=ARRAY['Apply right-triangle trigonometry and the Pythagorean theorem to surveying geometry.','Use the law of sines and law of cosines for oblique triangles.','Convert fluently among degrees, radians, and DMS, and between common surveying units.','Compute distance and direction between two coordinate points (the inverse).']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='74470d18-37e1-4928-a697-46927b811835';
DELETE FROM lesson_blocks WHERE lesson_id='74470d18-37e1-4928-a697-46927b811835';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Systematic errors follow a physical law and can be modeled/removed; random errors are unavoidable and follow the normal curve; mistakes must be found and discarded.','Accuracy = closeness to the true value (bias); precision = repeatability (scatter).','Standard deviation σ = sqrt(Σv²/(n−1)); standard deviation of the mean σ_m = σ/sqrt(n).','Error of a sum of independent quantities: E = sqrt(E1² + E2² + … ) (errors add in quadrature).']::text[], learning_objectives=ARRAY['Distinguish systematic errors, random errors, and mistakes (blunders), and the proper treatment of each.','Differentiate accuracy from precision and relate them to bias and scatter.','Compute the mean, residuals, standard deviation, and standard deviation of the mean for a set of observations.','Apply error propagation for sums and the rule for the error of a series and of the mean.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='fb89ec38-209b-4125-9acf-7de4d88465bc';
DELETE FROM lesson_blocks WHERE lesson_id='fb89ec38-209b-4125-9acf-7de4d88465bc';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Horizontal distance: H = S·cos(vertical angle) = S·sin(zenith angle). Zenith is measured from vertical (90° = level).','Steel tape temperature correction: Ct = α(T − T0)L with α = 0.00000645/°F; slope correction ≈ −h²/(2L).','Azimuths run 0–360° clockwise from north; convert quadrant bearings by quadrant (NE: Az = β; SE: 180 − β; SW: 180 + β; NW: 360 − β).','Geometric check: interior angles of a closed polygon sum to (n − 2)·180°; misclosure ÷ n = correction per angle.']::text[], learning_objectives=ARRAY['Reduce slope distance to horizontal using slope (vertical) angle or zenith angle.','Apply steel-tape corrections: temperature, tension/pull, sag, slope, and standardization.','Convert between quadrant bearings and azimuths and compute angles from directions.','Compute the angular misclosure of a closed traverse and the correction per angle.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6e515c6d-3835-4681-84ca-7ce2215b7c28';
DELETE FROM lesson_blocks WHERE lesson_id='6e515c6d-3835-4681-84ca-7ce2215b7c28';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['HI = known elevation + backsight (BS, a ''plus'' sight); new elevation = HI − foresight (FS, a ''minus'' sight).','A turning point (TP) carries the line forward — it receives a FS then a BS; the rod must stay on the same point.','Arithmetic check: Σ backsights − Σ foresights = final elevation − starting elevation.','Balancing BS and FS distances cancels collimation, curvature, and refraction errors.']::text[], learning_objectives=ARRAY['Apply the height-of-instrument method: HI = BM + BS; elevation = HI − FS.','Distinguish backsight, foresight, turning point, and the difference between intermediate sights and FS to TPs.','Compute and check level-loop misclosure and apply allowable-error criteria.','Identify and eliminate systematic leveling errors by balancing backsight and foresight distances.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b546fea7-83b5-4940-a51b-f02529e30b46';
DELETE FROM lesson_blocks WHERE lesson_id='b546fea7-83b5-4940-a51b-f02529e30b46';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['NAD83 is the horizontal datum (on the GRS80 ellipsoid); NAVD88 is the vertical datum (orthometric heights from the geoid).','Orthometric height H = ellipsoid height h − geoid height N (H = h − N).','Texas SPCS uses the Lambert Conformal Conic projection with five zones (N, NC, C, SC, S).','Combined factor = grid scale factor × elevation (sea-level) factor; ground distance = grid distance ÷ combined factor.']::text[], learning_objectives=ARRAY['Distinguish horizontal and vertical datums (NAD83, NAVD88) and the geoid vs. the ellipsoid.','Explain State Plane Coordinate Systems, Lambert vs. Transverse Mercator projections, and the Texas zones.','Apply grid, ground, and combined scale factors to convert between grid and ground distances.','Relate geodetic latitude/longitude, ellipsoid/orthometric/geoid heights, and convergence (mapping angle).']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12';
DELETE FROM lesson_blocks WHERE lesson_id='0fe093eb-d7ed-43a7-9511-fdaf7f6b0f12';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Latitude = distance·cos(azimuth); departure = distance·sin(azimuth). North/East positive; South/West negative.','Linear misclosure = sqrt((Σlat)² + (Σdep)²); for a closed loop the sums should be zero.','Relative precision = misclosure : perimeter, expressed as 1 : (perimeter ÷ misclosure).','Compass (Bowditch) rule: distribute misclosure to each course in proportion to its length.']::text[], learning_objectives=ARRAY['Compute latitudes and departures of traverse courses from bearings/azimuths and distances.','Determine the linear misclosure and relative precision (ratio of closure) of a traverse.','Adjust a traverse by the compass (Bowditch) rule and compute adjusted coordinates.','Apply the correct signs to latitudes and departures by quadrant.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='abf146f7-f77e-4d6c-a065-6de160ac604b';
DELETE FROM lesson_blocks WHERE lesson_id='abf146f7-f77e-4d6c-a065-6de160ac604b';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Shoelace area: A = ½·|Σ(x_i·y_{i+1} − x_{i+1}·y_i)|; convert ft² to acres by ÷ 43,560.','DMD area = ½·|Σ(DMD × latitude)|; DMD of a course = previous DMD + previous departure + present departure.','Trapezoidal rule: A = d·[(h0 + hn)/2 + (h1 + … + h_{n−1})]; Simpson''s ⅓ needs an even number of intervals.','Average-end-area volume V = L·(A1 + A2)/2; divide ft³ by 27 for cubic yards.']::text[], learning_objectives=ARRAY['Compute parcel area from coordinates using the shoelace (coordinate) method.','Compute area by the double-meridian-distance (DMD) method using latitudes and departures.','Estimate irregular areas by the trapezoidal rule and Simpson''s one-third rule.','Compute earthwork volumes by the average-end-area and prismoidal methods.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='e079ffe6-6bd0-499c-a406-a86b351ad5c2';
DELETE FROM lesson_blocks WHERE lesson_id='e079ffe6-6bd0-499c-a406-a86b351ad5c2';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GNSS positions by trilateration from satellite ranges; a 4th satellite solves the receiver clock bias, so 4 are needed for 3D.','Carrier-phase (cm-level, needs ambiguity resolution) is far more precise than code pseudorange (m-level).','Static/post-processed gives the highest accuracy; RTK gives real-time cm accuracy via a base/correction stream.','Lower DOP (well-spread satellites) means better accuracy; major errors are ionosphere, troposphere, orbit/clock, and multipath.']::text[], learning_objectives=ARRAY['Explain GNSS positioning by trilateration and the role of the receiver-clock bias (four-satellite minimum).','Distinguish code-pseudorange and carrier-phase observations and their accuracy levels.','Compare positioning methods: autonomous, DGPS, static, RTK, and network RTK.','Describe error sources and the effect of satellite geometry (DOP) on positioning accuracy.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='249bd04d-b9d0-455d-b416-023af3efc6b4';
DELETE FROM lesson_blocks WHERE lesson_id='249bd04d-b9d0-455d-b416-023af3efc6b4';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Work each problem by: identify the unknown and unit → pick the formula → check signs/quadrant → estimate → compute.','Carry a degree-mode calculator and watch zenith-vs-vertical angles and lat/dep signs.','For area, never forget the ½ and the ÷43,560; for curves, the tangent is R·tan(I/2).','Use the randomized problem templates in this module to drill speed and accuracy before exam day.']::text[], learning_objectives=ARRAY['Solve mixed, exam-style fundamentals problems under realistic time pressure.','Select the correct formula and units for distance, angle, traverse, area, and curve problems.','Self-check answers with estimates and unit reasoning.','Identify and correct the common point-losing mistakes flagged throughout this module.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97';
DELETE FROM lesson_blocks WHERE lesson_id='cd8225a2-c6f3-4e3c-a8df-5b8278d6cf97';
  'eeee2550-0000-0000-0000-000000000001', 'Right-triangle hypotenuse (Pythagorean theorem)', 'Right-triangle hypotenuse (Pythagorean theorem)', 'SIT Review — Mathematics', 'Right triangles', 'numeric_input', 'easy', 'A right triangle has legs measuring {{a:f2}} ft and {{b:f2}} ft. Using the Pythagorean theorem, what is the length of the hypotenuse, in feet?', 'hypot(a, b)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"a","type":"float","min":30,"max":300,"decimals":2},{"name":"b","type":"float","min":30,"max":300,"decimals":2}]'::jsonb, '[{"name":"aSq","formula":"a*a"},{"name":"bSq","formula":"b*b"}]'::jsonb, '[{"step_number":1,"title":"Square each leg","formula":"a^2 and b^2","calculation_template":"{{a:f2}}^2 = {{aSq:f2}}; {{b:f2}}^2 = {{bSq:f2}}"},{"step_number":2,"title":"Add and take the square root","result_template":"sqrt({{aSq:f2}} + {{bSq:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'By the Pythagorean theorem, c = sqrt(a^2 + b^2) = sqrt({{a:f2}}^2 + {{b:f2}}^2) = {{_answer}} ft. The hypotenuse is always longer than either leg.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000002', 'Convert a SE quadrant bearing to azimuth', 'Convert a SE quadrant bearing to azimuth', 'SIT Review — Angles and Directions', 'Bearing to azimuth', 'numeric_input', 'easy', 'A line has the quadrant bearing S {{b:dms}} E (south-and-east). Compute the AZIMUTH of the line (clockwise from north), in decimal degrees.', '180-b', '{"decimals":2,"unit":"deg","tolerance":0.1}', '[{"name":"b","type":"float","min":5,"max":85,"decimals":4}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Identify the quadrant","calculation_template":"S {{b:f2}} E -> SE quadrant (azimuth 90 to 180 deg)"},{"step_number":2,"title":"Apply the SE rule","formula":"azimuth = 180 - bearing angle","result_template":"180 - {{b:f2}} = {{_answer}} deg"}]'::jsonb, '{"method":"none"}'::jsonb, 'A southeast bearing converts to azimuth with azimuth = 180 - bearing angle = 180 - {{b:f2}} = {{_answer}} deg.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000003', 'Latitude of a traverse course', 'Latitude of a traverse course', 'SIT Review — Traverse', 'Latitude and departure', 'numeric_input', 'medium', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the LATITUDE (north-south component) of this course, in feet.', 'dist*cos(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":15,"max":75},{"name":"dist","type":"float","min":150,"max":650,"decimals":2}]'::jsonb, '[{"name":"dep","formula":"dist*sin(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Latitude formula","formula":"Lat = d cos(alpha)","calculation_template":"{{dist:f2}} x cos({{ang:f0}} deg)"},{"step_number":2,"title":"Compute","result_template":"Latitude = {{_answer}} ft (north, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Latitude = d cos(alpha) = {{dist:f2}} x cos({{ang:f0}} deg) = {{_answer}} ft north. (Its departure, d sin(alpha), would be {{dep:f2}} ft east.)', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000004', 'Linear misclosure of a closed traverse', 'Linear misclosure of a closed traverse', 'SIT Review — Traverse', 'Closure', 'numeric_input', 'medium', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE, in feet.', 'hypot(sumLat, sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumLat","type":"float","min":-0.18,"max":0.18,"decimals":3},{"name":"sumDep","type":"float","min":-0.18,"max":0.18,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure formula","formula":"E = sqrt(sumLat^2 + sumDep^2)","calculation_template":"sqrt(({{sumLat:f3}})^2 + ({{sumDep:f3}})^2)"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000005', 'Parcel area by coordinates (shoelace), in acres', 'Parcel area by coordinates (shoelace), in acres', 'SIT Review — Area', 'Shoelace method', 'numeric_input', 'medium', 'A closed four-sided parcel has corner coordinates (X, Y), in feet, of A(0, 0), B({{xb}}, 0), C({{xb}}, {{yc}}), and D(0, {{yd}}), taken counter-clockwise. Using the coordinate (shoelace) method, what is the parcel area in ACRES? (1 acre = 43,560 sq ft.)', '(0.5*abs(xb*(yc-0) + xb*(yd-0)))/43560', '{"decimals":3,"unit":"ac","tolerance":0.005}', '[{"name":"xb","type":"integer","min":300,"max":700},{"name":"yc","type":"integer","min":250,"max":600},{"name":"yd","type":"integer","min":250,"max":600}]'::jsonb, '[{"name":"areaSqFt","formula":"0.5*abs(xb*(yc-0) + xb*(yd-0))"}]'::jsonb, '[{"step_number":1,"title":"Apply the shoelace sum","formula":"2A = sum(x_i*y_{i+1} - x_{i+1}*y_i)","calculation_template":"Cross-multiply A(0,0), B({{xb}},0), C({{xb}},{{yc}}), D(0,{{yd}}) around the loop"},{"step_number":2,"title":"Double area in square feet","result_template":"2A = {{xb}}*{{yc}} + {{xb}}*{{yd}} ; A = {{areaSqFt:f1}} sq ft"},{"step_number":3,"title":"Convert to acres","result_template":"{{areaSqFt:f1}} / 43,560 = {{_answer}} ac"}]'::jsonb, '{"method":"none"}'::jsonb, 'The shoelace method yields a double area of {{xb}}*{{yc}} + {{xb}}*{{yd}}; halving gives {{areaSqFt:f1}} sq ft, which is {{areaSqFt:f1}} / 43,560 = {{_answer}} acres.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000006', 'EDM/steel-tape temperature correction', 'EDM/steel-tape temperature correction', 'SIT Review — Distance Measurement', 'Temperature correction', 'numeric_input', 'medium', 'A distance of {{L:f2}} ft is taped with a steel tape standardized at 68 degF. The field temperature is {{T:f1}} degF. Using alpha = 0.00000645 per degF, compute the TEMPERATURE CORRECTION (in feet) to be applied to the measured distance (give the signed value).', '0.00000645*(T-68)*L', '{"decimals":3,"unit":"ft","tolerance":0.005}', '[{"name":"L","type":"float","min":400,"max":1500,"decimals":2},{"name":"T","type":"float","min":30,"max":110,"decimals":1}]'::jsonb, '[{"name":"dT","formula":"T-68"}]'::jsonb, '[{"step_number":1,"title":"Temperature departure","formula":"T - T0","calculation_template":"{{T:f1}} - 68 = {{dT:f1}} degF"},{"step_number":2,"title":"Apply the correction formula","formula":"Ct = alpha (T - T0) L","calculation_template":"0.00000645 x {{dT:f1}} x {{L:f2}}"},{"step_number":3,"title":"Temperature correction","result_template":"Ct = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Ct = alpha (T - T0) L = 0.00000645 x ({{T:f1}} - 68) x {{L:f2}} = 0.00000645 x {{dT:f1}} x {{L:f2}} = {{_answer}} ft. A positive value means the tape was hotter than standard (longer), so the correction is added.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
  'eeee2550-0000-0000-0000-000000000007', 'Tangent length of a simple horizontal curve', 'Tangent length of a simple horizontal curve', 'SIT Review — Curves', 'Tangent length', 'numeric_input', 'medium', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}} degrees. What is the tangent length T (ft) from the PC to the PI?', 'R*tan(toRad(I/2))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":400,"max":1500},{"name":"I","type":"integer","min":10,"max":60}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Half the central angle","formula":"I / 2","calculation_template":"{{I}} deg / 2"},{"step_number":2,"title":"Tangent length","result_template":"T = {{R}} x tan({{I}} deg / 2) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The tangent distance from the PC to the PI of a simple curve is T = R*tan(I/2) = {{R}} x tan({{I}} deg / 2) = {{_answer}} ft. Remember to halve I before taking the tangent.', 'c1000019-0000-0000-0000-000000000019', ARRAY['buildout','module-25','practice']::text[], true, 'buildout:m25');
COMMIT;
SELECT 'm25 SIT Exam Review — Fundamentals: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000019-0000-0000-0000-000000000019') || ' blocks.' AS status;